import{_ as r,o as a,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"69. Breastfeeding","description":"","frontmatter":{"title":"69. Breastfeeding","eba":"Nurses and Midwives 2024-2028","topics":["flexible-work","hours","breaks"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/69-breastfeeding.md","filePath":"ebas/nurses-midwives/leave/69-breastfeeding.md"}'),i={name:"ebas/nurses-midwives/leave/69-breastfeeding.md"};function o(n,e,l,p,d,m){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_69-breastfeeding" tabindex="-1">69. Breastfeeding <a class="header-anchor" href="#_69-breastfeeding" aria-label="Permalink to &quot;69. Breastfeeding&quot;">​</a></h1><p><strong>69.1</strong> Paid break</p><p>Each Employer will provide reasonable paid break time for an Employee to express breast milk for her nursing child each time such Employee has need to express the milk, or breastfeed the child within the workplace, for one year after the child&#39;s birth.</p><p><strong>69.2</strong> Place to express or feed</p><p>Employers will also provide a comfortable place, other than a bathroom, that is shielded from view and free from intrusion from co-workers and the public, which may be used by an Employee to express breast milk or breastfeed a child in privacy.</p><p><strong>69.3</strong> Storage</p><p>Appropriate refrigeration will be available in proximity to the area for breast milk storage. Responsibility for labelling, storage and use is with the Employee.</p><p>Plain language terms: lactation breaks, pumping, expressing milk, nursing mothers.</p>',8)])])}const b=r(i,[["render",o]]);export{h as __pageData,b as default};
